import{_ as e,o,c as r,a2 as a}from"./chunks/framework.kxxRO88J.js";const c=JSON.parse('{"title":"4장. 프롬프트 쇼케이스","description":"","frontmatter":{"sidebar_position":1},"headers":[],"relativePath":"04-prompt-showcase/index.md","filePath":"04-prompt-showcase/index.md"}'),i={name:"04-prompt-showcase/index.md"};function l(n,t,s,d,h,p){return o(),r("div",null,[...t[0]||(t[0]=[a('<h1 id="_4장-프롬프트-쇼케이스" tabindex="-1">4장. 프롬프트 쇼케이스 <a class="header-anchor" href="#_4장-프롬프트-쇼케이스" aria-label="Permalink to &quot;4장. 프롬프트 쇼케이스&quot;">​</a></h1><h2 id="remotion-dev-prompts" tabindex="-1">remotion.dev/prompts <a class="header-anchor" href="#remotion-dev-prompts" aria-label="Permalink to &quot;remotion.dev/prompts&quot;">​</a></h2><p>Remotion 팀은 실제 프롬프트로 생성된 영상 예제를 공개적으로 공유하는 쇼케이스 사이트를 운영합니다.</p><p><strong><a href="https://www.remotion.dev/prompts" target="_blank" rel="noreferrer">https://www.remotion.dev/prompts</a></strong></p><p>이 사이트는 다음과 같은 정보를 제공합니다.</p><ul><li>실제로 사용된 프롬프트 텍스트</li><li>그 프롬프트가 생성한 영상 미리보기</li><li>다운로드 가능한 TypeScript 소스 코드</li><li>컴포지션 설정 (크기, fps, 길이)</li></ul><hr><h2 id="왜-쇼케이스를-먼저-확인해야-하는가" tabindex="-1">왜 쇼케이스를 먼저 확인해야 하는가 <a class="header-anchor" href="#왜-쇼케이스를-먼저-확인해야-하는가" aria-label="Permalink to &quot;왜 쇼케이스를 먼저 확인해야 하는가&quot;">​</a></h2><p>처음부터 프롬프트를 작성하는 것보다, 이미 검증된 예제에서 시작하는 것이 훨씬 효율적입니다.</p><p><strong>초보자에게 특히 유용한 이유:</strong></p><ol><li><strong>가능성의 범위 파악</strong>: Remotion+Codex로 어떤 종류의 영상이 만들어지는지 먼저 확인할 수 있습니다</li><li><strong>프롬프트 작성 패턴 학습</strong>: 전문가들이 프롬프트를 어떻게 구성하는지 직접 볼 수 있습니다</li><li><strong>코드 시작점 확보</strong>: 처음부터 작성하지 않고, 가장 가까운 예제 코드에서 시작할 수 있습니다</li><li><strong>실현 가능성 검증</strong>: 내가 원하는 효과가 이미 만들어진 적 있는지 확인할 수 있습니다</li></ol><hr><h2 id="이-챕터의-구성" tabindex="-1">이 챕터의 구성 <a class="header-anchor" href="#이-챕터의-구성" aria-label="Permalink to &quot;이 챕터의 구성&quot;">​</a></h2><table tabindex="0"><thead><tr><th>페이지</th><th>내용</th></tr></thead><tbody><tr><td><a href="./how-to-use.html">쇼케이스 활용법</a></td><td>사이트 탐색 방법과 예제 카테고리</td></tr><tr><td><a href="./download-and-customize.html">다운로드 및 커스터마이징</a></td><td>예제 코드를 내 프로젝트에 맞게 수정</td></tr></tbody></table><hr><h2 id="이-챕터를-마치면" tabindex="-1">이 챕터를 마치면 <a class="header-anchor" href="#이-챕터를-마치면" aria-label="Permalink to &quot;이 챕터를 마치면&quot;">​</a></h2><ul><li>remotion.dev/prompts에서 원하는 예제를 찾는 방법을 알게 됩니다</li><li>예제 코드를 다운로드해 Codex로 커스터마이징하는 방법을 익힙니다</li><li>한국어 제품 소개 영상에 맞게 프롬프트 예제를 변형하는 실습을 완료합니다</li></ul>',17)])])}const _=e(i,[["render",l]]);export{c as __pageData,_ as default};
